import { describe, it } from "node:test";
import assert from "node:assert";
import { bytesToHex, hexToBytes, u128ToLeBytes, leBytesToU128 } from "./utils.js";
describe("utils", () => {
    it("round-trips hex", () => {
        const bytes = new Uint8Array([0, 1, 255, 128]);
        assert.deepStrictEqual(hexToBytes(bytesToHex(bytes)), bytes);
    });
    it("serializes u128 little-endian", () => {
        const n = 0x123456789abcdef0n;
        const bytes = u128ToLeBytes(n);
        assert.strictEqual(bytes.length, 16);
        assert.strictEqual(leBytesToU128(bytes), n);
    });
});
